class Solution(object):
    def evenOddBit(self, n):
        even, odd = 0, 0
        bit_index = 0
        while n:
            if n & 1:
                if bit_index % 2 == 0:
                    even += 1
                else:
                    odd += 1
            n >>= 1
            bit_index += 1
        return [even, odd]
